+    async fn regression_auth_cooldown_skips_repeat() {
+        use std::sync::atomic::{AtomicU64, Ordering};
+        static CTR: AtomicU64 = AtomicU64::new(0);
+        let n = CTR.fetch_add(1, Ordering::SeqCst);
+        let db_path = std::env::temp_dir().join(format!(
